+/**
+ * Integration tests for the full notification pipeline.
+ *
+ * Tests the end-to-end flow: domain event → NotificationService → adapters
+ * (email, SMS, webhook) → history logging, with user preferences enforcement.
+ *
+ * Unlike unit tests, these tests wire up all real components (EventBus,
+ * NotificationService, adapters, PreferencesService, NotificationHistoryService)
+ * and only stub the transport layer (the actual send mechanism).
+ */
+
+import { describe, it, expect, beforeEach } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import { Database } from '../../src/utils/database.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import {
+  NotificationHistoryService,
+  resetNotificationLogIdCounter,
+} from '../../src/services/notification-history.service.js';
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import {
+  PreferencesService,
+  resetPreferencesIdCounter,
+} from '../../src/services/preferences.service.js';
+import { EmailAdapter } from '../../src/adapters/email.adapter.js';
+import type { EmailMessage, EmailTransport } from '../../src/adapters/email.adapter.js';
+import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
+import type { SmsMessage, SmsTransport } from '../../src/adapters/sms.adapter.js';
+import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
+import type { WebhookPayload, WebhookTransport } from '../../src/adapters/webhook.adapter.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
+import type { Order } from '../../src/models/order.js';
+import type { User } from '../../src/models/user.js';
+
+// ---------------------------------------------------------------------------
+// Test helpers
+// ---------------------------------------------------------------------------
+
+function makeOrder(overrides: Partial<Order> = {}): Order {
+  return {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+    total: 20,
+    status: 'pending',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function makeUser(overrides: Partial<User> = {}): User {
+  return {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+/** Creates a spy EmailTransport that records sent messages. */
+function createEmailTransport() {
+  const sent: EmailMessage[] = [];
+  const transport: EmailTransport = {
+    async sendMail(msg) {
+      sent.push(msg);
+      return { messageId: `email-${sent.length}` };
+    },
+  };
+  return { transport, sent };
+}
+
+/** Creates a spy SmsTransport that records sent messages. */
+function createSmsTransport() {
+  const sent: SmsMessage[] = [];
+  const transport: SmsTransport = {
+    async sendSms(msg) {
+      sent.push(msg);
+      return { messageId: `sms-${sent.length}` };
+    },
+  };
+  return { transport, sent };
+}
+
+/** Creates a spy WebhookTransport that records POSTed payloads. */
+function createWebhookTransport() {
+  const sent: { url: string; payload: WebhookPayload; headers: Record<string, string> }[] = [];
+  const transport: WebhookTransport = {
+    async post(url, payload, headers) {
+      sent.push({ url, payload, headers });
+      return { statusCode: 200 };
+    },
+  };
+  return { transport, sent };
+}
+
+// ---------------------------------------------------------------------------
+// Integration test suite
+// ---------------------------------------------------------------------------
+
+describe('Notification Pipeline — Integration', () => {
+  let db: Database;
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let historyService: NotificationHistoryService;
+  let preferencesService: PreferencesService;
+  let logRepo: NotificationLogRepository;
+  let prefsRepo: PreferencesRepository;
+
+  // Spy transports
+  let emailTx: ReturnType<typeof createEmailTransport>;
+  let smsTx: ReturnType<typeof createSmsTransport>;
+  let webhookTx: ReturnType<typeof createWebhookTransport>;
+
+  beforeEach(() => {
+    // Reset ID counters
+    resetNotificationIdCounter();
+    resetNotificationLogIdCounter();
+    resetPreferencesIdCounter();
+
+    // Shared infra
+    db = new Database();
+    eventBus = new EventBus();
+
+    // Repositories
+    logRepo = new NotificationLogRepository(db);
+    prefsRepo = new PreferencesRepository(db);
+
+    // Services — order matters: history subscribes to events before
+    // notification service emits them (both subscribe in constructor).
+    historyService = new NotificationHistoryService(logRepo, eventBus);
+    notificationService = new NotificationService(eventBus);
+
+    // Preferences
+    preferencesService = new PreferencesService(prefsRepo);
+    notificationService.setPreferencesService(preferencesService);
+
+    // Adapters with spy transports
+    emailTx = createEmailTransport();
+    smsTx = createSmsTransport();
+    webhookTx = createWebhookTransport();
+
+    notificationService.registerAdapter(
+      new EmailAdapter({ fromAddress: 'noreply@taskflow.io', transport: emailTx.transport }),
+    );
+    notificationService.registerAdapter(
+      new SmsAdapter({ fromNumber: '+15551234567', transport: smsTx.transport }),
+    );
+    notificationService.registerAdapter(
+      new WebhookAdapter({
+        url: 'https://hooks.example.com/notify',
+        secret: 'test-secret',
+        transport: webhookTx.transport,
+      }),
+    );
+  });
+
+  // -----------------------------------------------------------------------
+  // 1. Email channel — end-to-end
+  // -----------------------------------------------------------------------
+  describe('email notification delivery', () => {
+    it('should deliver email when user has email preferences enabled', async () => {
+      // Email is enabled by default for new users
+      preferencesService.getOrCreatePreferences('user-1');
+
+      const event: OrderCreatedEvent = {
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      };
+
+      await eventBus.emit(event);
+
+      // Email transport should have received the message
+      expect(emailTx.sent).toHaveLength(1);
+      expect(emailTx.sent[0]!.to).toBe('alice@example.com');
+      expect(emailTx.sent[0]!.subject).toBe('Order Confirmation: order-1');
+      expect(emailTx.sent[0]!.from).toBe('noreply@taskflow.io');
+      // HTML template should contain the order body
+      expect(emailTx.sent[0]!.html).toContain('Order Confirmation');
+    });
+
+    it('should not send email when user has disabled email channel', async () => {
+      preferencesService.updateEmailPreferences('user-1', { enabled: false });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(emailTx.sent).toHaveLength(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 2. SMS channel — end-to-end
+  // -----------------------------------------------------------------------
+  describe('SMS notification delivery', () => {
+    it('should deliver SMS when user has SMS preferences enabled', async () => {
+      // SMS is disabled by default — explicitly enable it
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(smsTx.sent).toHaveLength(1);
+      expect(smsTx.sent[0]!.from).toBe('+15551234567');
+      expect(smsTx.sent[0]!.body).toContain('Order Confirmation');
+    });
+
+    it('should not send SMS when user has SMS disabled (default)', async () => {
+      // SMS is disabled by default — do NOT enable it
+      preferencesService.getOrCreatePreferences('user-1');
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(smsTx.sent).toHaveLength(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 3. Webhook channel — end-to-end
+  // -----------------------------------------------------------------------
+  describe('webhook notification delivery', () => {
+    it('should deliver webhook when user has webhook preferences enabled', async () => {
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(webhookTx.sent).toHaveLength(1);
+      expect(webhookTx.sent[0]!.url).toBe('https://hooks.example.com/notify');
+      expect(webhookTx.sent[0]!.payload.event).toBe('order_confirmation');
+      expect(webhookTx.sent[0]!.payload.recipient).toBe('alice@example.com');
+      expect(webhookTx.sent[0]!.headers['Authorization']).toBe('Bearer test-secret');
+      expect(webhookTx.sent[0]!.headers['Content-Type']).toBe('application/json');
+    });
+
+    it('should not send webhook when user has webhook disabled (default)', async () => {
+      preferencesService.getOrCreatePreferences('user-1');
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(webhookTx.sent).toHaveLength(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 4. Notification history logging
+  // -----------------------------------------------------------------------
+  describe('notification history', () => {
+    it('should log successful deliveries for each channel', async () => {
+      // Enable all channels
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // History should have 3 entries (one per channel)
+      expect(historyService.getCount()).toBe(3);
+
+      const emailLogs = historyService.query({ channel: 'email' });
+      expect(emailLogs).toHaveLength(1);
+      expect(emailLogs[0]!.status).toBe('sent');
+      expect(emailLogs[0]!.notificationType).toBe('order_confirmation');
+
+      const smsLogs = historyService.query({ channel: 'sms' });
+      expect(smsLogs).toHaveLength(1);
+      expect(smsLogs[0]!.status).toBe('sent');
+
+      const webhookLogs = historyService.query({ channel: 'webhook' });
+      expect(webhookLogs).toHaveLength(1);
+      expect(webhookLogs[0]!.status).toBe('sent');
+    });
+
+    it('should log failed deliveries when adapter returns failure', async () => {
+      // Replace email adapter with one that fails
+      notificationService.registerAdapter({
+        channel: 'email',
+        async send() {
+          return { success: false, channel: 'email', error: 'SMTP auth failed' };
+        },
+      });
+
+      preferencesService.getOrCreatePreferences('user-1');
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      const failedLogs = historyService.query({ status: 'failed' });
+      expect(failedLogs).toHaveLength(1);
+      expect(failedLogs[0]!.error).toBe('SMTP auth failed');
+      expect(failedLogs[0]!.channel).toBe('email');
+    });
+
+    it('should log failed deliveries when adapter throws', async () => {
+      notificationService.registerAdapter({
+        channel: 'email',
+        async send() {
+          throw new Error('Network unreachable');
+        },
+      });
+
+      preferencesService.getOrCreatePreferences('user-1');
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      const failedLogs = historyService.query({ status: 'failed' });
+      expect(failedLogs).toHaveLength(1);
+      expect(failedLogs[0]!.error).toBe('Network unreachable');
+    });
+
+    it('should record metadata from the notification in the log', async () => {
+      preferencesService.getOrCreatePreferences('user-1');
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      const logs = historyService.getByRecipient('alice@example.com');
+      expect(logs).toHaveLength(1);
+      expect(logs[0]!.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 5. User preferences enforcement
+  // -----------------------------------------------------------------------
+  describe('user preferences enforcement', () => {
+    it('should only send to channels the user has enabled', async () => {
+      // Enable email and webhook, leave SMS disabled
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(emailTx.sent).toHaveLength(1);
+      expect(smsTx.sent).toHaveLength(0);
+      expect(webhookTx.sent).toHaveLength(1);
+      expect(historyService.getCount()).toBe(2);
+    });
+
+    it('should suppress all channels when all are disabled', async () => {
+      preferencesService.updateEmailPreferences('user-1', { enabled: false });
+      // SMS and webhook are already disabled by default
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(emailTx.sent).toHaveLength(0);
+      expect(smsTx.sent).toHaveLength(0);
+      expect(webhookTx.sent).toHaveLength(0);
+      expect(notificationService.getNotificationCount()).toBe(0);
+      expect(historyService.getCount()).toBe(0);
+    });
+
+    it('should respect per-category subscriptions', async () => {
+      // Enable email but unsubscribe from order_confirmation
+      preferencesService.updateEmailPreferences('user-1', {
+        enabled: true,
+        subscribedCategories: ['order_status_update', 'welcome', 'account_updated'],
+      });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // order_confirmation should be suppressed
+      expect(emailTx.sent).toHaveLength(0);
+
+      // But order_status_update should go through
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      } satisfies OrderStatusChangedEvent);
+
+      expect(emailTx.sent).toHaveLength(1);
+    });
+
+    it('should allow all notifications when no preferences are stored (email only)', async () => {
+      // Don't create preferences at all — email defaults to allowed, SMS/webhook default to denied
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(emailTx.sent).toHaveLength(1);
+      expect(smsTx.sent).toHaveLength(0);
+      expect(webhookTx.sent).toHaveLength(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 6. Notification ordering
+  // -----------------------------------------------------------------------
+  describe('notification ordering', () => {
+    it('should deliver notifications in the order events are emitted', async () => {
+      const deliveryOrder: string[] = [];
+
+      // Replace email adapter with one that tracks delivery order with variable latency
+      notificationService.registerAdapter({
+        channel: 'email',
+        async send(payload) {
+          // First notification takes longer but should still be delivered first
+          const delay = payload.notificationType === 'order_confirmation' ? 50 : 10;
+          await new Promise((resolve) => setTimeout(resolve, delay));
+          deliveryOrder.push(payload.notificationType);
+          return { success: true, channel: 'email' };
+        },
+      });
+
+      preferencesService.getOrCreatePreferences('user-1');
+
+      // Emit order:created first, then order:status-changed
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      } satisfies OrderStatusChangedEvent);
+
+      expect(deliveryOrder).toEqual(['order_confirmation', 'order_status_update']);
+    });
+
+    it('should dispatch to channels in registration order', async () => {
+      const channelOrder: string[] = [];
+
+      // Replace all adapters with tracking versions
+      notificationService.registerAdapter({
+        channel: 'email',
+        async send() {
+          channelOrder.push('email');
+          return { success: true, channel: 'email' };
+        },
+      });
+      notificationService.registerAdapter({
+        channel: 'sms',
+        async send() {
+          channelOrder.push('sms');
+          return { success: true, channel: 'sms' };
+        },
+      });
+      notificationService.registerAdapter({
+        channel: 'webhook',
+        async send() {
+          channelOrder.push('webhook');
+          return { success: true, channel: 'webhook' };
+        },
+      });
+
+      // Enable all channels
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      expect(channelOrder).toEqual(['email', 'sms', 'webhook']);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // 7. Multi-channel and cross-cutting scenarios
+  // -----------------------------------------------------------------------
+  describe('multi-channel scenarios', () => {
+    it('should send order_status_update through all enabled channels', async () => {
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'shipped' }),
+        previousStatus: 'confirmed',
+        newStatus: 'shipped',
+        timestamp: new Date(),
+      } satisfies OrderStatusChangedEvent);
+
+      expect(emailTx.sent).toHaveLength(1);
+      expect(smsTx.sent).toHaveLength(1);
+      expect(webhookTx.sent).toHaveLength(1);
+
+      // Verify content correctness per channel
+      expect(emailTx.sent[0]!.subject).toBe('Order Update: order-1');
+      expect(smsTx.sent[0]!.body).toContain('Order Update');
+      expect(webhookTx.sent[0]!.payload.event).toBe('order_status_update');
+      expect(webhookTx.sent[0]!.payload.body).toContain('confirmed');
+      expect(webhookTx.sent[0]!.payload.body).toContain('shipped');
+    });
+
+    it('should handle partial adapter failure gracefully', async () => {
+      // Email adapter throws, SMS succeeds, webhook succeeds
+      notificationService.registerAdapter({
+        channel: 'email',
+        async send() {
+          throw new Error('SMTP down');
+        },
+      });
+
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+      preferencesService.updateWebhookPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // SMS and webhook should still have succeeded
+      expect(smsTx.sent).toHaveLength(1);
+      expect(webhookTx.sent).toHaveLength(1);
+
+      // History should show 1 failure + 2 successes
+      const allLogs = historyService.query({});
+      expect(allLogs).toHaveLength(3);
+      expect(historyService.query({ status: 'failed' })).toHaveLength(1);
+      expect(historyService.query({ status: 'sent' })).toHaveLength(2);
+    });
+
+    it('should track notification count correctly across channels', async () => {
+      preferencesService.updateEmailPreferences('user-1', { enabled: true });
+      preferencesService.updateSmsPreferences('user-1', { enabled: true });
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // 2 channels enabled (email + SMS), webhook disabled
+      expect(notificationService.getNotificationCount()).toBe(2);
+      expect(notificationService.getNotifications().every((n) => n.status === 'sent')).toBe(true);
+    });
+
+    it('should support multiple sequential events for the same user', async () => {
+      preferencesService.getOrCreatePreferences('user-1');
+
+      // First: order created
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // Second: status change
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      } satisfies OrderStatusChangedEvent);
+
+      // Third: another status change
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'shipped' }),
+        previousStatus: 'confirmed',
+        newStatus: 'shipped',
+        timestamp: new Date(),
+      } satisfies OrderStatusChangedEvent);
+
+      expect(emailTx.sent).toHaveLength(3);
+      expect(historyService.getCount()).toBe(3);
+
+      const types = historyService.query({}).map((l) => l.notificationType);
+      expect(types).toEqual([
+        'order_confirmation',
+        'order_status_update',
+        'order_status_update',
+      ]);
+    });
+
+    it('should isolate preferences between different users', async () => {
+      // user-1 has email enabled, SMS disabled (defaults)
+      preferencesService.getOrCreatePreferences('user-1');
+      // user-2 has email disabled, SMS enabled
+      preferencesService.updateEmailPreferences('user-2', { enabled: false });
+      preferencesService.updateSmsPreferences('user-2', { enabled: true });
+
+      // Notify user-1
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder({ userId: 'user-1' }),
+        user: makeUser({ id: 'user-1', email: 'alice@example.com' }),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // Notify user-2
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder({ id: 'order-2', userId: 'user-2' }),
+        user: makeUser({ id: 'user-2', email: 'bob@example.com' }),
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // user-1 gets email only
+      expect(emailTx.sent.filter((m) => m.to === 'alice@example.com')).toHaveLength(1);
+      expect(smsTx.sent.filter((m) => m.to === 'alice@example.com')).toHaveLength(0);
+
+      // user-2 gets SMS only
+      expect(emailTx.sent.filter((m) => m.to === 'bob@example.com')).toHaveLength(0);
+      expect(smsTx.sent.filter((m) => m.to === 'bob@example.com')).toHaveLength(1);
+    });
+  });
+});

